diff --git a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
index 6babfd1eee91..615ca510f329 100644
--- a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
+++ b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
@@ -7254,6 +7254,41 @@ static bool
 planContainsAdditionalSimplifications(VPlan &Plan, ElementCount VF,
                                       VPCostContext &CostCtx, Loop *TheLoop,
                                       LoopVectorizationCostModel &CM) {
+  // Fast path: detect trivially constant conditional branch conditions stemming
+  // from truncation of an OR with a constant that has LSB set. For example:
+  //   %t = trunc i8 (or i8 %x, C) to i1
+  //   br i1 %t, ...
+  // where C & 1 != 0, which makes the condition always true. VPlan can fold this
+  // but the legacy cost-model may not account for it. If such a pattern exists
+  // anywhere in the loop, consider it an additional simplification.
+  for (BasicBlock *BB : TheLoop->blocks()) {
+    for (Instruction &I : *BB) {
+      auto *Br = dyn_cast<BranchInst>(&I);
+      if (!Br || !Br->isConditional())
+        continue;
+      Value *Cond = Br->getCondition();
+      auto LSBSet = [](Value *V) {
+        if (auto *CI = dyn_cast<ConstantInt>(V))
+          return CI->getBitWidth() > 0 && (CI->getZExtValue() & 1ULL);
+        return false;
+      };
+      if (auto *Tr = dyn_cast<TruncInst>(Cond)) {
+        Value *Src = Tr->getOperand(0);
+        if (auto *BO = dyn_cast<BinaryOperator>(Src)) {
+          if (BO->getOpcode() == Instruction::Or) {
+            if (LSBSet(BO->getOperand(0)) || LSBSet(BO->getOperand(1)))
+              return true;
+          }
+        }
+      } else if (auto *BO = dyn_cast<BinaryOperator>(Cond)) {
+        if (BO->getOpcode() == Instruction::Or && Cond->getType()->isIntegerTy(1)) {
+          if (LSBSet(BO->getOperand(0)) || LSBSet(BO->getOperand(1)))
+            return true;
+        }
+      }
+    }
+  }
+
   // First collect all instructions for the recipes in Plan.
   auto GetInstructionForCost = [](const VPRecipeBase *R) -> Instruction * {
     if (auto *S = dyn_cast<VPSingleDefRecipe>(R))
@@ -7289,6 +7324,35 @@ planContainsAdditionalSimplifications(VPlan &Plan, ElementCount VF,
         return any_of(*BB, [&SeenInstrs, VF, &CostCtx, &CM](Instruction &I) {
           if (isa<PHINode>(&I))
             return false;
+
+          // Treat trivially constant branch conditions as extra simplification,
+          // even if the legacy cost model would skip costing them. For example:
+          //   br i1 (trunc (or %x, C) to i1), ...
+          // where C has its least significant bit set, making the condition true.
+          if (auto *Br = dyn_cast<BranchInst>(&I)) {
+            if (Br->isConditional()) {
+              Value *Cond = Br->getCondition();
+              auto LSBSet = [](Value *V) {
+                if (auto *CI = dyn_cast<ConstantInt>(V))
+                  return CI->getBitWidth() > 0 && (CI->getZExtValue() & 1ULL);
+                return false;
+              };
+              if (auto *Tr = dyn_cast<TruncInst>(Cond)) {
+                Value *Src = Tr->getOperand(0);
+                if (auto *BO = dyn_cast<BinaryOperator>(Src)) {
+                  if (BO->getOpcode() == Instruction::Or) {
+                    if (LSBSet(BO->getOperand(0)) || LSBSet(BO->getOperand(1)))
+                      return true;
+                  }
+                }
+              } else if (auto *BO = dyn_cast<BinaryOperator>(Cond)) {
+                if (BO->getOpcode() == Instruction::Or && Cond->getType()->isIntegerTy(1)) {
+                  if (LSBSet(BO->getOperand(0)) || LSBSet(BO->getOperand(1)))
+                    return true;
+                }
+              }
+            }
+          }
           return !SeenInstrs.contains(&I) &&
                  !CostCtx.skipCostComputation(&I, true) &&
                  !CM.canTruncateToMinimalBitwidth(&I, VF);
@@ -7362,11 +7426,13 @@ VectorizationFactor LoopVectorizationPlanner::computeBestVF() {
   VPCostContext CostCtx(CM.TTI, *CM.TLI, Legal->getWidestInductionType(),
                         LLVMCtx, CM);
   precomputeCosts(BestPlan, BestFactor.Width, CostCtx);
-  assert((BestFactor.Width == LegacyVF.Width ||
+    assert((BestFactor.Width == LegacyVF.Width ||
           planContainsAdditionalSimplifications(getPlanFor(BestFactor.Width),
                                                 BestFactor.Width, CostCtx,
                                                 OrigLoop, CM)) &&
          " VPlan cost model and legacy cost model disagreed");
+
+
   assert((BestFactor.Width.isScalar() || BestFactor.ScalarCost > 0) &&
          "when vectorizing, the scalar cost must be computed.");
 #endif

